 96→
 97→/* Animated mesh gradient background */
 98→.mesh-gradient {
 99→  background:
100→    radial-gradient(ellipse at 20% 50%, rgba(99, 102, 241, 0.15) 0%, transparent 50%),
101→    radial-gradient(ellipse at 80% 20%, rgba(139, 92, 246, 0.12) 0%, transparent 50%),
102→    radial-gradient(ellipse at 50% 80%, rgba(6, 182, 212, 0.1) 0%, transparent 50%),
103→    #0a0a1a;
104→  background-size: 100% 100%;
105→  animation: meshShift 20s ease-in-out infinite;
106→}
107→
108→@keyframes meshShift {
109→  0%, 100% {
110→    background-position: 0% 0%, 100% 0%, 50% 100%;
111→  }
112→  33% {
113→    background-position: 50% 50%, 0% 100%, 100% 0%;
114→  }
115→  66% {
116→    background-position: 100% 0%, 50% 50%, 0% 50%;
117→  }
118→}
119→
120→/* Glassmorphism utilities */
121→.glass {
122→  background: rgba(255, 255, 255, 0.05);
123→  backdrop-filter: blur(20px);
124→  -webkit-backdrop-filter: blur(20px);
125→  border: 1px solid rgba(255, 255, 255, 0.1);
126→}
127→
128→.glass-strong {
129→  background: rgba(255, 255, 255, 0.08);
130→  backdrop-filter: blur(30px);
131→  -webkit-backdrop-filter: blur(30px);
132→  border: 1px solid rgba(255, 255, 255, 0.12);
133→}
134→
135→.glass-card {
136→  background: rgba(255, 255, 255, 0.04);
137→  backdrop-filter: blur(16px);
138→  -webkit-backdrop-filter: blur(16px);
139→  border: 1px solid rgba(255, 255, 255, 0.08);
140→  transition: all 0.3s ease;
141→}
142→
143→.glass-card:hover {
144→  background: rgba(255, 255, 255, 0.07);
145→  border-color: rgba(255, 255, 255, 0.15);
146→  box-shadow: 0 8px 32px rgba(139, 92, 246, 0.1);
147→  transform: translateY(-2px);
148→}
149→
150→/* Gradient text */
151→.gradient-text {
152→  background: linear-gradient(135deg, #8b5cf6, #6366f1, #06b6d4);
153→  -webkit-background-clip: text;
154→  -webkit-text-fill-color: transparent;
155→  background-clip: text;
156→}
157→
158→/* Gradient button */
159→.gradient-btn {
160→  background: linear-gradient(135deg, #8b5cf6, #6366f1);
161→  position: relative;
162→  overflow: hidden;
163→  transition: all 0.3s ease;
164→}
165→
166→.gradient-btn:hover {
167→  box-shadow: 0 0 30px rgba(139, 92, 246, 0.4);
168→  transform: translateY(-1px);
169→}
170→
171→.gradient-btn::after {
172→  content: '';
173→  position: absolute;
174→  top: -50%;
175→  left: -50%;
176→  width: 200%;
177→  height: 200%;
178→  background: linear-gradient(
179→    45deg,
180→    transparent 30%,
181→    rgba(255, 255, 255, 0.1) 50%,
182→    transparent 70%
183→  );
184→  animation: shine 3s ease-in-out infinite;
185→  pointer-events: none;
186→}
187→
188→@keyframes shine {
189→  0% { transform: translateX(-100%) rotate(45deg); }
190→  100% { transform: translateX(100%) rotate(45deg); }
191→}
192→
193→/* Glow effects */
194→.glow-purple { box-shadow: 0 0 20px rgba(139, 92, 246, 0.2); }
195→.glow-blue { box-shadow: 0 0 20px rgba(99, 102, 241, 0.2); }
196→.glow-cyan { box-shadow: 0 0 20px rgba(6, 182, 212, 0.2); }
197→.glow-green { box-shadow: 0 0 20px rgba(16, 185, 129, 0.2); }
198→.glow-red { box-shadow: 0 0 20px rgba(239, 68, 68, 0.2); }
199→
200→/* Animations */
201→@keyframes fadeUp {
202→  from { opacity: 0; transform: translateY(20px); }
203→  to { opacity: 1; transform: translateY(0); }
204→}
205→
206→@keyframes fadeIn {
207→  from { opacity: 0; }
208→  to { opacity: 1; }
209→}
210→
211→@keyframes scaleIn {
212→  from { opacity: 0; transform: scale(0.95); }
213→  to { opacity: 1; transform: scale(1); }
214→}
215→
216→@keyframes pulse-glow {
217→  0%, 100% { opacity: 0.5; }
218→  50% { opacity: 1; }
219→}
220→
221→.animate-fade-up {
222→  animation: fadeUp 0.6s ease-out forwards;
223→}
224→
225→.animate-fade-in {
226→  animation: fadeIn 0.5s ease-out forwards;
227→}
228→
229→.animate-scale-in {
230→  animation: scaleIn 0.4s ease-out forwards;
231→}
232→
233→.delay-100 { animation-delay: 0.1s; }
234→.delay-200 { animation-delay: 0.2s; }
235→.delay-300 { animation-delay: 0.3s; }
236→.delay-400 { animation-delay: 0.4s; }
237→
238→/* Dot grid pattern overlay */
239→.dot-grid {
240→  background-image: radial-gradient(rgba(255, 255, 255, 0.05) 1px, transparent 1px);
241→  background-size: 24px 24px;
242→}
243→
244→/* Gradient border for inputs */
245→.gradient-border {
246→  position: relative;
247→  background: rgba(255, 255, 255, 0.04);
248→  border: 1px solid rgba(255, 255, 255, 0.1);
249→  transition: all 0.3s ease;
250→}
251→
252→.gradient-border:focus-within {
253→  border-color: rgba(139, 92, 246, 0.5);
254→  box-shadow: 0 0 0 3px rgba(139, 92, 246, 0.1);
255→}
256→
257→/* Chat markdown styling */
258→.chat-markdown h3 {
259→  font-size: 0.9rem;
260→  font-weight: 700;
261→  color: rgba(255, 255, 255, 0.9);
262→  margin-top: 1rem;
263→  margin-bottom: 0.4rem;
264→}
265→
266→.chat-markdown h4 {
267→  font-size: 0.85rem;
268→  font-weight: 600;
269→  color: rgba(255, 255, 255, 0.85);
270→  margin-top: 0.75rem;
271→  margin-bottom: 0.3rem;
272→}
273→
274→.chat-markdown p {
275→  margin-bottom: 0.5rem;
276→}
277→
278→.chat-markdown strong {
279→  color: rgba(255, 255, 255, 0.95);
280→  font-weight: 600;
281→}
282→
283→.chat-markdown em {
284→  color: rgba(167, 139, 250, 0.9);
285→  font-style: italic;
286→}
287→
288→.chat-markdown ul,
289→.chat-markdown ol {
290→  margin: 0.4rem 0;
291→  padding-left: 1.25rem;
292→}
293→
294→.chat-markdown li {
295→  margin-bottom: 0.25rem;
296→}
297→
298→.chat-markdown li::marker {
299→  color: rgba(139, 92, 246, 0.6);
300→}
301→
302→.chat-markdown hr {
303→  border: none;
304→  border-top: 1px solid rgba(255, 255, 255, 0.08);
305→  margin: 0.75rem 0;
306→}
307→
308→.chat-markdown code {
309→  background: rgba(255, 255, 255, 0.08);
310→  padding: 0.15rem 0.4rem;
311→  border-radius: 4px;
312→  font-size: 0.8rem;
313→  color: rgba(196, 181, 253, 0.9);
314→}
315→
316→.chat-markdown blockquote {
317→  border-left: 3px solid rgba(139, 92, 246, 0.5);
318→  padding-left: 0.75rem;
319→  margin: 0.5rem 0;
320→  color: rgba(255, 255, 255, 0.5);
321→}
322→
323→/* Scrollbar styling */
324→::-webkit-scrollbar {
325→  width: 6px;
326→}
327→
328→::-webkit-scrollbar-track {
329→  background: transparent;
330→}
331→
332→::-webkit-scrollbar-thumb {
333→  background: rgba(255, 255, 255, 0.1);
334→  border-radius: 3px;
335→}
336→
337→::-webkit-scrollbar-thumb:hover {
338→  background: rgba(255, 255, 255, 0.2);
339→}
