  1→"use client";
  2→
  3→import { Star, User, CheckCircle2 } from "lucide-react";
  4→import { Review } from "@/types";
  5→import { cn } from "@/lib/utils";
  6→
  7→interface ReviewCardProps {
  8→  review: Review;
  9→  index: number;
 10→}
 11→
 12→const sentimentConfig = {
 13→  POSITIVE: {
 14→    badge: "bg-emerald-500/15 text-emerald-400 border-emerald-500/20",
 15→    border: "border-l-emerald-500",
 16→    glow: "shadow-emerald-500/5",
 17→  },
 18→  NEGATIVE: {
 19→    badge: "bg-red-500/15 text-red-400 border-red-500/20",
 20→    border: "border-l-red-500",
 21→    glow: "shadow-red-500/5",
 22→  },
 23→  NEUTRAL: {
 24→    badge: "bg-slate-500/15 text-slate-400 border-slate-500/20",
 25→    border: "border-l-slate-500",
 26→    glow: "shadow-slate-500/5",
 27→  },
 28→  MIXED: {
 29→    badge: "bg-amber-500/15 text-amber-400 border-amber-500/20",
 30→    border: "border-l-amber-500",
 31→    glow: "shadow-amber-500/5",
 32→  },
 33→};
 34→
 35→export default function ReviewCard({ review, index }: ReviewCardProps) {
 36→  const sentiment = review.sentiment?.label;
 37→  const config = sentiment ? sentimentConfig[sentiment] : null;
 38→
 39→  return (
 40→    <div
 41→      className={cn(
 42→        "glass-card rounded-xl p-4 group border-l-[3px]",
 43→        config ? `${config.border} ${config.glow}` : "border-l-white/10"
 44→      )}
 45→    >
 46→      <div className="flex items-start justify-between gap-3">
 47→        <div className="flex-1 min-w-0">
 48→          <div className="flex items-center gap-2 mb-1.5 flex-wrap">
 49→            <span className="text-[10px] text-white/25 font-mono bg-white/5 px-1.5 py-0.5 rounded">
 50→              #{index + 1}
 51→            </span>
 52→            <div className="flex items-center">
 53→              {Array.from({ length: 5 }).map((_, i) => (
 54→                <Star
 55→                  key={i}
 56→                  className={cn(
 57→                    "w-3.5 h-3.5",
 58→                    i < review.rating
 59→                      ? "fill-amber-400 text-amber-400"
 60→                      : "text-white/10"
 61→                  )}
 62→                />
 63→              ))}
 64→            </div>
 65→            {sentiment && config && (
 66→              <span
 67→                className={cn(
 68→                  "text-[10px] px-2 py-0.5 rounded-full border font-semibold uppercase tracking-wider",
 69→                  config.badge
 70→                )}
 71→              >
 72→                {sentiment.toLowerCase()}
 73→              </span>
 74→            )}
 75→            {review.sentiment && (
 76→              <span className="text-[10px] text-white/20 font-mono">
 77→                {(review.sentiment.score * 100).toFixed(0)}%
 78→              </span>
 79→            )}
 80→          </div>
 81→          {review.title && (
 82→            <h4 className="font-semibold text-sm text-white/80 mb-1 line-clamp-1">
 83→              {review.title}
 84→            </h4>
 85→          )}
 86→          <p className="text-sm text-white/40 line-clamp-3 leading-relaxed">
 87→            {review.body}
 88→          </p>
 89→          <div className="flex items-center gap-3 mt-2.5 text-xs text-white/25">
