 18→export default function IngestForm() {
 19→  const router = useRouter();
 20→  const fileInputRef = useRef<HTMLInputElement>(null);
 21→
 22→  const [url, setUrl] = useState("");
 23→  const [csvText, setCsvText] = useState("");
 24→  const [productName, setProductName] = useState("");
 25→  const [platform, setPlatform] = useState("Amazon");
 26→  const [loading, setLoading] = useState(false);
 27→  const [error, setError] = useState("");
 28→  const [fileName, setFileName] = useState("");
 29→
 30→  const handleUrlSubmit = async () => {
 31→    if (!url.trim()) {
 32→      setError("Please enter a product URL");
 33→      return;
 34→    }
 35→    await submitIngest({ type: "url", url: url.trim(), platform });
 36→  };
 37→
 38→  const handleCsvSubmit = async () => {
 39→    if (!csvText.trim()) {
 40→      setError("Please paste CSV data or upload a file");
 41→      return;
 42→    }
 43→    await submitIngest({
 44→      type: "csv",
 45→      csvData: csvText.trim(),
 46→      productName: productName.trim() || "Uploaded Product",
 47→      platform,
 48→    });
 49→  };
 50→
 51→  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
 52→    const file = e.target.files?.[0];
 53→    if (!file) return;
 54→    setFileName(file.name);
 55→    const reader = new FileReader();
 56→    reader.onload = (event) => {
 57→      setCsvText(event.target?.result as string);
 58→    };
 59→    reader.readAsText(file);
 60→  };
 61→
 62→  const submitIngest = async (body: Record<string, string>) => {
 63→    setLoading(true);
 64→    setError("");
 65→    try {
 66→      const res = await fetch("/api/ingest", {
 67→        method: "POST",
 68→        headers: { "Content-Type": "application/json" },
 69→        body: JSON.stringify(body),
 70→      });
 71→      const data = await res.json();
 72→      if (!res.ok || !data.success) {
 73→        setError(data.error || "Failed to ingest reviews");
 74→        return;
 75→      }
 76→      sessionStorage.setItem("reviewlens_session", data.sessionId);
 77→      sessionStorage.setItem("reviewlens_metadata", JSON.stringify(data.metadata));
 78→      sessionStorage.setItem("reviewlens_reviews", JSON.stringify(data.reviews));
 79→      sessionStorage.setItem("reviewlens_analytics", JSON.stringify(data.analytics));
 80→      router.push("/dashboard");
 81→    } catch {
 82→      setError("Network error. Please try again.");
 83→    } finally {
 84→      setLoading(false);
