 1→"use client";
 2→
 3→interface KeywordsCloudProps {
 4→  keywords: { word: string; count: number }[];
 5→}
 6→
 7→export default function KeywordsCloud({ keywords }: KeywordsCloudProps) {
 8→  if (keywords.length === 0) return null;
 9→
10→  const maxCount = keywords[0]?.count || 1;
11→
12→  const getStyle = (count: number) => {
13→    const ratio = count / maxCount;
14→    if (ratio > 0.7) return "text-sm font-bold text-violet-300 bg-violet-500/15 border-violet-500/20";
15→    if (ratio > 0.4) return "text-xs font-semibold text-indigo-300 bg-indigo-500/10 border-indigo-500/15";
16→    return "text-xs font-medium text-white/50 bg-white/5 border-white/10";
17→  };
18→
19→  return (
20→    <div className="glass-card rounded-xl p-6">
21→      <h3 className="text-lg font-semibold text-white/90 mb-4">Top Keywords</h3>
22→      <div className="flex flex-wrap gap-2">
23→        {keywords.map((kw) => (
24→          <span
25→            key={kw.word}
26→            className={`px-3 py-1 rounded-full border cursor-default transition-all hover:scale-105 ${getStyle(kw.count)}`}
27→          >
28→            {kw.word}
29→            <span className="ml-1.5 opacity-50">{kw.count}</span>
30→          </span>
31→        ))}
32→      </div>
33→    </div>
34→  );
35→}
