16→export default function ChatDrawer({ open, onClose, sessionId, metadata }: ChatDrawerProps) {
17→  // Lock body scroll when drawer is open
18→  useEffect(() => {
19→    if (open) {
20→      document.body.style.overflow = "hidden";
21→    } else {
22→      document.body.style.overflow = "";
23→    }
24→    return () => {
25→      document.body.style.overflow = "";
26→    };
27→  }, [open]);
28→
29→  // Close on Escape
30→  useEffect(() => {
31→    const handleKey = (e: KeyboardEvent) => {
32→      if (e.key === "Escape") onClose();
33→    };
34→    if (open) window.addEventListener("keydown", handleKey);
35→    return () => window.removeEventListener("keydown", handleKey);
36→  }, [open, onClose]);
