45→        )}
46→        onClick={onClose}
47→      />
48→
49→      {/* Drawer panel */}
50→      <div
51→        className={cn(
52→          "fixed top-0 right-0 h-full w-full sm:w-[85vw] lg:w-[75vw] xl:w-[65vw] z-50 transition-transform duration-300 ease-out",
53→          open ? "translate-x-0" : "translate-x-full"
54→        )}
55→      >
